ost'', ''=C8'', None, None, None)\n(None, ''Less: Your contribution ($/mo × months)'', ''=-C9*C6'', None, None, None)\n(None, \"MOM''S NET COST — OPTION A\", ''=C20+C21'', None, None, None)\n(None, None, None, None, None, None)\n(None, ''OPTION B: BUY CAR, SELL AFTER SUMMER'', None, None, None, None)\n(None, ''Item'', ''Cost'', ''Formula'', None, None)\n(None, ''Buy-sell transaction spread loss'', ''=C7*C12'', ''Price × spread %'', None, None)\n(None, ''Additional depreciation (age/miles)'', ''=C7*C13'', ''Price × extra dep %'', None, None)\n(None, ''Sales tax (not recovered on resale)'', ''=C7*C10'', ''Price × tax rate'', None, None)\n(None, ''Title, registration, DMV fees'', ''=C11'', None, None, None)\n(None, ''Insurance (4 months)'', ''=C14*C6'', ''Monthly × months'', None, None)\n(None, ''Budgeted repairs / maintenance'', ''=C15'', None, None, None)\n(None, ''Opportunity cost: $22K not invested'', ''=C7*C16*(C6/12)'', ''Price × return × time'', None, None)\n(None, \"MOM''S COST — OPTION B\", ''=SUM(C26:C32)'', None, None, None)\n(None, None, None, None, None, None)\n(None, \"BOTTOM LINE — MOM''S OUT-OF-POCKET COST\", None, None, None, None)\n(None, ''Option A — Rent (net of your contribution)'', ''=C22'', None, None, None)\n(None, ''Option B — Buy and sell'', ''=C33'', None, None, None)\n(None, \"Mom''s savings with Option A\", ''=C33-C22'', None, None, None)\n(None, ''Better option for Mom'', ''=IF(C38>0,\"RENT (Option A)\",IF(C38<0,\"BUY (Option B)\",\"TIED\"))'', None, None, None)\n(None, None, None, None, None, None)\n(None, ''YOUR COST (what you pay)'', None, None, None, None)\n(None, ''Your total contribution (Option A)'', ''=C9*C6'', None, None, None)\n(None, ''Your contribution (Option B)'', 0, None, None, None)\n(None, None, None, None, None, None)\n(None, ''RISKS NOT IN THE NUMBERS (all against Option B)'', None, None, None, None)\n(None, ''• Major mechanical failure: one transmission/engine/AC issue = $2,000-$5,000 beyond the reserve.'', None, None, 