	('6503f3cd-77f7-4fe6-9b73-aa647eabd2e1', 'ae6275c4-6918-4909-ab6a-8fc318669419', 'sevt_015rtYXJh1s9SEyLMcXUJAXy', 'agent.message', '{"id": "sevt_015rtYXJh1s9SEyLMcXUJAXy", "type": "agent.message", "content": [{"text": "Ah, I see the issue! Your presentation file is 291 MB — it''s a bit too chunky to work with directly. The good news is I can help you access it through a sync process. Let me try reading the PPTX skill again:", "type": "text"}], "processed_at": "2026-05-10T03:17:45.100Z"}', '2026-05-10 03:17:45.1+00', '2026-05-10 03:18:38.063379+00'),
